# Apply synthesis routes
for name, route in SYNTHESIS_ROUTES.items():
    if name in DRUG_DB:
        DRUG_DB[name]['synthesis_verified'] = True
        DRUG_DB[name]['synthesis'] = route

# Update DRUG_DATA list
for drug in DRUG_DATA:
    if drug['name'] in DRUG_DB:
        drug['synthesis_verified'] = DRUG_DB[drug['name']].get('synthesis_verified', False)
        drug['synthesis'] = DRUG_DB[drug['name']].get('synthesis', [])

# Final stats
total = len(DRUG_DB)
with_synth = sum(1 for d in DRUG_DATA if d.get('synthesis_verified'))
print(f"\n=== FINAL DATABASE STATS ===")
print(f"Total drugs: {total}")
print(f"With verified synthesis routes: {with_synth}")
cats = {}
for d in DRUG_DATA:
    cat = d.get('category', 'Unknown')
    cats[cat] = cats.get(cat, 0) + 1
print(f"Categories: {len(cats)}")
for cat, count in sorted(cats.items(), key=lambda x: -x[1])[:15]:
    print(f"  {cat}: {count}")
